/**
 * sme-monitor.js
 * SME Mission Control Dashboard v2 Ã¢â‚¬â€ server + embedded HTML UI
 *
 * Usage : node sme-monitor.js
 * Opens : http://localhost:9999
 *
 * Control APIs:
 *   POST /api/action  { action: 'start'|'stop', name: '<component-name>' }
 *   POST /api/run-script  { script: 'prep'|'boot'|'fullboot' }
 *
 * The embedded <script> uses NO ES6 template literals to avoid collision
 * with the outer Node.js template literal that injects PROJECT_ROOT.
 */
'use strict';

const http  = require('http');
const https = require('https');
const net   = require('net');
const { execSync, spawn } = require('child_process');
const fs    = require('fs');
const path  = require('path');

// Service directory + npm script map (mirrors ecosystem.config.js).
// Services are started / stopped directly without any external process manager.
const SERVICE_SCRIPT_MAP = {
  'api-gateway':    { dir: 'apps/api-gateway',    script: 'start:dev' },
  'iam-service':    { dir: 'apps/iam-service',    script: 'start:dev' },
  'tenant-service': { dir: 'apps/tenant-service', script: 'start:dev' },
  'config-service': { dir: 'apps/config-service', script: 'start:dev' },
  'audit-service':  { dir: 'apps/audit-service',  script: 'start:dev' },
  'portal-service': { dir: 'apps/portal-service', script: 'start:dev' },
  'web-admin':      { dir: 'apps/web-admin',      script: 'dev' },
  'web-portal':     { dir: 'apps/web-portal',     script: 'dev' },
};

// ── PID Registry — logs/sme-registry.json ───────────────────────────────────
// Written by sme-fullboot.ps1 (Stage 3/4) and by startServiceDirect.
// Format: { "iam-service": 12345, "tenant-service": 67890, ... }
function readPidRegistry() {
  try { return JSON.parse(fs.readFileSync(REGISTRY_FILE, 'utf8')); } catch (_) { return {}; }
}
function writePidRegistry(name, pid) {
  var reg = readPidRegistry();
  reg[name] = pid;
  try { fs.writeFileSync(REGISTRY_FILE, JSON.stringify(reg, null, 2), 'utf8'); } catch (_) {}
}
function clearPidRegistry(name) {
  var reg = readPidRegistry();
  delete reg[name];
  try { fs.writeFileSync(REGISTRY_FILE, JSON.stringify(reg, null, 2), 'utf8'); } catch (_) {}
}

// ── PID liveness — WMI "double lock" validates BOTH existence AND identity ───
// Two-stage check:
//   1. process.kill(pid, 0) — fast Windows OpenProcess; confirms PID is live.
//   2. wmic CommandLine check — confirms the live process is actually our
//      service and not an unrelated app that Windows recycled the PID to.
//      We verify the commandline contains the service directory substring
//      (e.g. "apps/iam-service" or "apps\iam-service") so VS Code extensions,
//      Chrome, and other node workers can never be a false positive.
//
// NOTE: On Windows, processes spawned via Node.js spawn() with windowsHide:true
// (and cmd.exe wrapper processes) often appear with an empty CommandLine in WMI.
// When the CommandLine value is empty, identity verification is not possible and
// we fall back to the process.kill(pid,0) existence check to avoid false negatives.
// Falls back to false on any error — always safe to re-launch.
function isNodeAlive(pid, serviceName) {
  if (!pid || pid <= 0) return false;
  // Stage 1: fast existence check — avoid the heavier WMI call if PID is gone.
  // On Windows, EPERM means "process exists but caller lacks signal permission" — still alive.
  // ESRCH (or any other code) means the process does not exist.
  try { process.kill(pid, 0); } catch (e) {
    if (e && e.code === 'EPERM') {
      // Process IS alive — fall through to Stage 2 WMI identity check
    } else {
      return false; // ESRCH or other error — process is gone
    }
  }
  // Stage 2: WMI CommandLine identity check
  if (!serviceName) return true; // no name provided — caller opted out of identity check
  var svcSlug = 'apps' + path.sep + serviceName; // e.g. apps\iam-service
  var svcSlugFwd = 'apps/' + serviceName;        // forward-slash variant
  try {
    var out = require('child_process').execSync(
      'wmic process where (processid=' + parseInt(pid, 10) + ') get commandline /format:list',
      { encoding: 'utf8', timeout: 4000, windowsHide: true }
    );
    // Parse "CommandLine=<value>" from the WMI /format:list output (strips CRLF noise).
    var rawOut = (out || '').replace(/\r/g, '');
    var lineMatch = rawOut.match(/CommandLine=(.*)/i);
    var cmdlineValue = lineMatch ? lineMatch[1].trim() : '';
    // If WMI returned an empty CommandLine, identity verification is not possible
    // (Windows limitation: cmd.exe/node.exe spawned via spawn() with windowsHide:true
    // often have no readable CommandLine via wmic). Fall back to Stage 1 result.
    if (!cmdlineValue) return true;
    var cmdline = cmdlineValue.toLowerCase();
    return cmdline.indexOf(svcSlug.toLowerCase()) !== -1 ||
           cmdline.indexOf(svcSlugFwd.toLowerCase()) !== -1;
  } catch (_) { return false; }
}

// ── Registry self-heal — "Catch and Verify" two-step PID resolution ──────────
//
// Step 1 CATCH   : netstat -ano  → scan for the PID in LISTENING state on this
//                  exact port; uses a strict regex so :3001 never matches :30011.
//
// Step 2 VERIFY  : Get-CimInstance Win32_Process (modern CIM, not legacy wmic)
//                  → asserts BOTH:
//                    a) Process Name = node.exe
//                    b) CommandLine contains service folder slug OR project root
//                  Failure triggers a [SECURITY] Rogue-process warning in the
//                  event log. Empty CommandLine (windowsHide spawn side-effect)
//                  is accepted on node.exe name alone, with a console notice.
//
// Step 3 REGISTER: Caller (auto-heal pass) writes the verified PID to
//                  sme-registry.json and clears the "PID unresolved" warning.
//
// Returns the integer PID on success, or null on any failure/mismatch.
function discoverPidByPort(port, serviceName) {
  var p = parseInt(port, 10);

  // ── Step 1: CATCH ─────────────────────────────────────────────────────────
  // netstat -ano columns: Proto  Local-Address  Foreign-Address  State  PID
  // Strict port match: :<port> followed by whitespace so :3000 != :30001.
  var candidatePid = null;
  try {
    var nsOut = require('child_process').execSync(
      'netstat -ano',
      { encoding: 'utf8', timeout: 5000, windowsHide: true }
    );
    var portPattern = new RegExp(':' + p + '\\s');
    var lines = (nsOut || '').split('\n');
    for (var i = 0; i < lines.length; i++) {
      var line = lines[i].trim();
      if (!line || line.indexOf('LISTENING') === -1) continue;
      if (!portPattern.test(line)) continue;
      var parts = line.split(/\s+/);
      var pid = parseInt(parts[parts.length - 1], 10);
      if (pid > 0) { candidatePid = pid; break; }
    }
  } catch (e) {
    console.error('[PID-Catch] netstat error for ' + serviceName + ':' + p + ': ' + (e.message || e));
    return null;
  }

  if (!candidatePid) {
    console.log('[PID-Catch] No LISTENING process on :' + p + ' for ' + serviceName);
    return null;
  }
  console.log('[PID-Catch] Candidate PID ' + candidatePid + ' on :' + p + ' for ' + serviceName);

  // ── Step 2: VERIFY ────────────────────────────────────────────────────────
  // Get-CimInstance is the modern, reliable replacement for wmic.
  // It returns CommandLine correctly for node.exe even when windowsHide:true
  // was used during spawn (where legacy wmic often returns an empty string).
  // execFileSync with an explicit args array avoids all shell quoting hazards.
  var processName = null;
  var commandLine = '';
  try {
    var psCmd =
      '$proc = Get-CimInstance Win32_Process -Filter "ProcessId = ' + candidatePid + '" | ' +
      'Select-Object -First 1; ' +
      'if ($proc) { $proc.Name + "##SME##" + [string]$proc.CommandLine } else { "##NOT_FOUND##" }';
    var psOut = require('child_process').execFileSync(
      'powershell.exe',
      ['-NonInteractive', '-NoProfile', '-Command', psCmd],
      { encoding: 'utf8', timeout: 6000, windowsHide: true }
    );
    var result = (psOut || '').trim();
    if (!result || result === '##NOT_FOUND##') {
      console.log('[PID-Verify] PID ' + candidatePid + ' disappeared before CimInstance query (' + serviceName + ')');
      return null;
    }
    var delimIdx = result.indexOf('##SME##');
    processName  = delimIdx !== -1 ? result.substring(0, delimIdx).trim() : result.trim();
    commandLine  = delimIdx !== -1 ? result.substring(delimIdx + 7).trim() : '';
  } catch (e) {
    console.error('[PID-Verify] CimInstance error for PID ' + candidatePid + ' (' + serviceName + '): ' + (e.message || e));
    return null;
  }

  // Identity assertion 1: MUST be node.exe
  if (!processName || processName.toLowerCase() !== 'node.exe') {
    logMonitorEvent(
      '[SECURITY] Rogue process detected on port ' + p + ' for ' + serviceName +
      ': expected node.exe, got "' + (processName || 'unknown') + '" (PID ' + candidatePid + ')'
    );
    return null;
  }

  // Identity assertion 2: CommandLine must reference the service folder OR project root.
  // Accepted patterns: "apps\<service>", "apps/<service>", or the full PROJECT_ROOT path.
  var svcSlug     = ('apps' + path.sep + serviceName).toLowerCase(); // e.g. apps\iam-service
  var svcSlugFwd  = ('apps/' + serviceName).toLowerCase();           // e.g. apps/iam-service
  var projectFrag = PROJECT_ROOT.toLowerCase();
  var cmd         = commandLine.toLowerCase();

  if (cmd) {
    var knownPath = cmd.indexOf(svcSlug) !== -1 ||
                    cmd.indexOf(svcSlugFwd) !== -1 ||
                    cmd.indexOf(projectFrag) !== -1;
    if (!knownPath) {
      logMonitorEvent(
        '[SECURITY] Rogue process detected on port ' + p + ' for ' + serviceName +
        ': node.exe PID ' + candidatePid + ' CommandLine has no SME project path.' +
        ' cmd=' + commandLine.substring(0, 200)
      );
      return null;
    }
  } else {
    // CIM returned empty CommandLine — node.exe name is still a strong identity
    // signal for a self-heal scenario; accept but make it visible in the log.
    console.log('[PID-Verify] ' + serviceName + ': node.exe PID ' + candidatePid
      + ' — empty CommandLine (windowsHide spawn); accepting by process name');
  }

  // ── Step 3: REGISTER ─────────────────────────────────────────────────────
  console.log('[PID-Verify] ' + serviceName + ': identity confirmed — node.exe PID ' + candidatePid + ' on :' + p);
  return candidatePid;
}

// ── Log archival — move existing service logs to logs/archive/ ───────────────
// Renames <name>.out.log and <name>.err.log to archive/<name>_<kind>_<ts>.log.
// Start-Process (in fullboot) and fs.openSync (here) then create a fresh file.
function archiveServiceLog(name) {
  var logsDir    = path.join(PROJECT_ROOT, 'logs', 'services');
  var archiveDir = path.join(PROJECT_ROOT, 'logs', 'archive');
  if (!fs.existsSync(archiveDir)) { try { fs.mkdirSync(archiveDir, { recursive: true }); } catch (_) {} }
  ['out', 'err'].forEach(function (kind) {
    var src = path.join(logsDir, name + '.' + kind + '.log');
    if (fs.existsSync(src)) {
      var ts  = Date.now();
      var dst = path.join(archiveDir, name + '_' + kind + '_' + ts + '.log');
      try { fs.renameSync(src, dst); } catch (_) {}
    }
  });
}

// Kill the process (if any) listening on a given TCP port.
function killByPort(port) {
  try {
    // Use taskkill /F which can terminate elevated processes that Stop-Process cannot.
    execSync(
      'powershell -NonInteractive -Command "' +
      '$p = (netstat -ano | Select-String \":\' + port + \'\\\\s+\" | Select-String LISTENING | ' +
      'ForEach-Object { ($_.ToString().Trim() -split \"\\\\s+\")[-1] } | Select-Object -First 1); ' +
      'if ($p -match \"^\\\\d+$\") { ' +
        'try { & taskkill /F /PID ([int]$p) 2>$null | Out-Null } catch {}; ' +
        'Stop-Process -Id ([int]$p) -Force -ErrorAction SilentlyContinue }"',
      { timeout: 8000, windowsHide: true, cwd: PROJECT_ROOT }
    );
  } catch (e) { /* nothing listening on that port */ }
}

// Spawn a service as a detached background process, log to logs/services/<name>.{out,err}.log
// Idempotent: if a registered PID for this service is still alive, returns immediately.
function startServiceDirect(name) {
  const entry = SERVICE_SCRIPT_MAP[name];
  if (!entry) return { ok: false, message: 'No script mapping for service: ' + name };

  // Idempotency check — WMI double-lock: PID must exist AND belong to this service.
  const reg = readPidRegistry();
  if (reg[name] && isNodeAlive(reg[name], name)) {
    return { ok: true, message: name + ' is already running (PID ' + reg[name] + '). Nothing to do.' };
  }

  const svcDir  = path.join(PROJECT_ROOT, entry.dir.replace(/\//g, path.sep));
  const logsDir = path.join(PROJECT_ROOT, 'logs', 'services');
  if (!fs.existsSync(logsDir)) { try { fs.mkdirSync(logsDir, { recursive: true }); } catch (_) {} }

  // Archive existing logs before opening fresh file handles.
  // This eliminates the Set-Content race condition against slow-dying processes.
  archiveServiceLog(name);

  const outFile = path.join(logsDir, name + '.out.log');
  const errFile = path.join(logsDir, name + '.err.log');
  try {
    const out   = fs.openSync(outFile, 'w');
    const err   = fs.openSync(errFile, 'w');
    const child = spawn((process.env.ComSpec || 'cmd.exe'), ['/c', 'npm run ' + entry.script], {
      cwd:         svcDir,
      env:         process.env,
      stdio:       ['ignore', out, err],
      windowsHide: true,
    });
    child.unref();
    // Register PID so Stop uses targeted kill and next Start is idempotent.
    if (child.pid) writePidRegistry(name, child.pid);
    return { ok: true, message: name + ' started (PID ' + child.pid + '). Log: logs/services/' + name + '.out.log' };
  } catch (e) {
    return { ok: false, message: 'Failed to start ' + name + ': ' + e.message };
  }
}

