const MONITOR_PORT        = 9999;
const PROJECT_ROOT        = path.resolve(__dirname);
const HEALTH_TIMEOUT      = 1500; // ms  (wall-clock timeout per probe)
const REGISTRY_FILE       = path.join(PROJECT_ROOT, 'logs', 'sme-registry.json');
const MONITOR_EVENTS_LOG  = path.join(PROJECT_ROOT, 'logs', 'services', 'monitor-events.log');

// ── Per-service previous-state map — drives state-transition logging ─────────
// Populated after every gatherStatus cycle. Keys are service names.
const previousStates = {}; // { [name]: 'running' | 'booting' | 'stopped' }

// Ensure the logs/services directory exists (created lazily on first write)
function ensureEventLogDir() {
  var dir = path.dirname(MONITOR_EVENTS_LOG);
  if (!fs.existsSync(dir)) { try { fs.mkdirSync(dir, { recursive: true }); } catch (_) {} }
}

// Append a timestamped entry to logs/services/monitor-events.log.
function logMonitorEvent(msg) {
  try {
    ensureEventLogDir();
    var line = '[' + new Date().toISOString() + '] ' + msg + '\n';
    fs.appendFileSync(MONITOR_EVENTS_LOG, line, 'utf8');
    console.log('[monitor-event] ' + msg);
  } catch (_) {}
}

