// Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// ── Redis L7 probe — RESP PING/PONG (replaces bare TCP connect) ─────────────
// Connects via net.Socket, writes 'PING\r\n', asserts response contains 'PONG'.
// Only 'pong' result indicates the Redis instance is alive and serving commands.
function probeRedisPing(port) {
  return new Promise(function (resolve) {
    var sock    = new net.Socket();
    var settled = false;
    function done(result) {
      if (!settled) {
        settled = true;
        clearTimeout(timer);
        sock.destroy();
        resolve(result);
      }
    }
    var timer = setTimeout(function () { done('timeout'); }, HEALTH_TIMEOUT);
    sock.connect(port, '127.0.0.1', function () {
      sock.write('PING\r\n');
    });
    sock.on('data', function (data) {
      // Redis replies: '+PONG\r\n' (inline) or '$4\r\nPONG\r\n' (bulk)
      var reply = data.toString();
      done(reply.indexOf('PONG') !== -1 ? 'pong' : 'error');
    });
    sock.on('error', function () { done('error'); });
  });
}

// ── Docker Engine API probe — Windows named pipe (replaces docker info CLI) ───
// Sends GET /info to the Docker Engine REST API via the Windows named pipe.
// Zero subprocesses spawned. Returns true if HTTP 200 received.
function probeDockerDaemon() {
  return new Promise(function (resolve) {
    var settled = false;
    function done(ok) { if (!settled) { settled = true; clearTimeout(timer); resolve(ok); } }
    var timer = setTimeout(function () { done(false); }, HEALTH_TIMEOUT);
    var req = http.request(
      {
        socketPath: '\\\\.\\pipe\\docker_engine',
        path:       '/info',
        method:     'GET',
      },
      function (res) { res.resume(); done(res.statusCode === 200); }
    );
    req.on('error', function () { done(false); });
    req.end();
  });
}

// Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// HTTP health probe  Ã¢â€ â€™  { code: number|'timeout'|null, ok: boolean }
// Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// ── Dual-stack HTTP probe — IPv4 first, IPv6 fallback ────────────────────────
// Node.js does NOT automatically fall back across address families on
// ECONNREFUSED the way browsers do. A NestJS/Next.js service bound on
// 0.0.0.0:PORT answers on 127.0.0.1 but NOT on ::1, while a service bound
// on :::PORT answers on ::1. Probing only one address causes false "No response"
// failures when the service is fully operational.
//
// Strategy:
//  1. Try 127.0.0.1 (IPv4) with HEALTH_TIMEOUT budget.
//  2. If the socket errors (ECONNREFUSED / ECONNRESET / any network error),
//     immediately retry on [::1] (IPv6) with the remaining wall-clock budget.
//     A timeout counts as a definitive answer — we do NOT retry on timeout.
//  3. Return the first successful response (any HTTP status).
//
// The total wall-clock budget is capped at HEALTH_TIMEOUT so the caller's
// Promise.all phase never stalls longer than one cycle period.
function _probeSingleHost(hostname, port, urlPath, timeoutMs) {
  return new Promise(function (resolve) {
    var done = false;
    function finish(r) { if (!done) { done = true; clearTimeout(wall); resolve(r); } }
    var wall = setTimeout(function () {
      try { req.destroy(); } catch (_) {}
      finish({ code: 'timeout', ok: false, timedOut: true });
    }, timeoutMs);
    var req = http.request(
      { hostname: hostname, port: port, path: urlPath, method: 'GET' },
      function (res) {
        res.resume();
        finish({ code: res.statusCode, ok: res.statusCode < 500, timedOut: false });
      }
    );
    req.on('error', function (e) {
      finish({ code: null, ok: false, timedOut: false, err: e.code || e.message });
    });
    req.end();
  });
}

function probeHttp(port, urlPath) {
  urlPath = urlPath || '/health';
  var started = Date.now();
  // Attempt 1: IPv4 loopback
  return _probeSingleHost('127.0.0.1', port, urlPath, HEALTH_TIMEOUT).then(function (r4) {
    // Success or timeout — return immediately, do not retry on timeout.
    if (r4.ok || r4.timedOut || r4.code !== null) return r4;
    // Socket-level error (ECONNREFUSED etc.) — try IPv6 with remaining budget.
    var elapsed   = Date.now() - started;
    var remaining = Math.max(HEALTH_TIMEOUT - elapsed, 300); // at least 300 ms
    return _probeSingleHost('::1', port, urlPath, remaining).then(function (r6) {
      if (r6.code !== null || r6.timedOut) return r6; // IPv6 answered (even with HTTP error)
      // Both failed at network level — return IPv4 result (ECONNREFUSED is the cleaner signal)
      return r4;
    });
  });
}

// ── Infra local version detection ──────────────────────────────────────────────
function detectInfraVersion(name) {
  return new Promise(function (resolve) {
    var cmdMap = {
      'Docker':     'docker version --format "{{.Server.Version}}"',
      'Redis':      'docker exec sme-redis redis-cli info server',
      'RabbitMQ':   'docker exec sme-rabbitmq rabbitmqctl version',
      'PostgreSQL': 'psql --version',
    };
    var cmd = cmdMap[name];
    if (!cmd) return resolve(null);
    require('child_process').exec(cmd, { encoding: 'utf8', timeout: 1500, windowsHide: true },
      function (err, stdout) {
        if (err || !String(stdout).trim()) return resolve(null);
        var out = String(stdout).trim();
        try {
          if (name === 'Redis') {
            var m = out.match(/redis_version:([^\r\n]+)/);
            return resolve(m ? m[1].trim() : null);
          }
          if (name === 'Docker')     return resolve(out.split('\n')[0].trim() || null);
          if (name === 'RabbitMQ')   return resolve(out.split('\n')[0].trim() || null);
          if (name === 'PostgreSQL') {
            var pm = out.match(/(\d+\.\d+(?:\.\d+)?)/); return resolve(pm ? pm[1] : null);
          }
        } catch (_) {}
        resolve(null);
      }
    );
  });
}

// ── Latest version cache (fetched from internet, refreshed every 6 h) ───────
var LATEST_VER_CACHE = { data: {}, fetchedAt: 0 };
var LATEST_VER_TTL   = 6 * 3600 * 1000;

function httpsGetJson(urlStr) {
  return new Promise(function (resolve) {
    var m = String(urlStr).match(/^https:\/\/([^/]+)(\/.*)?$/);
    if (!m) return resolve(null);
    var opts = {
      hostname: m[1],
      path:     m[2] || '/',
      method:   'GET',
      headers:  { 'User-Agent': 'sme-monitor/1.0', 'Accept': 'application/vnd.github.v3+json' },
    };
    var req = https.request(opts, function (res) {
      if (res.statusCode !== 200) { res.resume(); return resolve(null); }
      var body = '';
      res.setEncoding('utf8');
      res.on('data', function (c) { body += c; if (body.length > 65536) { req.destroy(); } });
      res.on('end',  function () { try { resolve(JSON.parse(body)); } catch (_) { resolve(null); } });
    });
    req.setTimeout(8000, function () { req.destroy(); resolve(null); });
    req.on('error', function () { resolve(null); });
    req.end();
  });
}

function fetchLatestVersions() {
  return Promise.all([
    httpsGetJson('https://endoflife.date/api/postgresql.json'),
    httpsGetJson('https://api.github.com/repos/moby/moby/releases/latest'),
    httpsGetJson('https://api.github.com/repos/redis/redis/releases/latest'),
    httpsGetJson('https://api.github.com/repos/rabbitmq/rabbitmq-server/releases/latest'),
  ]).then(function (r) {
    var d = {};
    try { if (r[0] && r[0].length)  d['PostgreSQL'] = r[0][0].latest || null; }                  catch (_) {}
    try { if (r[1] && r[1].tag_name) d['Docker']     = r[1].tag_name.replace(/^v/, ''); }         catch (_) {}
    try { if (r[2] && r[2].tag_name) d['Redis']      = r[2].tag_name.replace(/^v/, ''); }         catch (_) {}
    try { if (r[3] && r[3].tag_name) d['RabbitMQ']   = r[3].tag_name.replace(/^v/, '').replace(/^rabbitmq-/, ''); } catch (_) {}
    LATEST_VER_CACHE.data = d;
    LATEST_VER_CACHE.fetchedAt = Date.now();
    console.log('[monitor] latest versions fetched:', JSON.stringify(d));
    return d;
  }).catch(function (e) {
    console.error('[monitor] fetchLatestVersions failed:', e.message);
    return LATEST_VER_CACHE.data;
  });
}

function startVersionRefreshLoop() {
  fetchLatestVersions();
  setInterval(function () { fetchLatestVersions(); }, LATEST_VER_TTL);
}

// ── Infrastructure version cache — populated ONCE at startup (Fix W1/W6) ─────
// Zero CLI commands run during the 8-second polling loop.
// Docker/Redis/PostgreSQL: one CLI call at startup. RabbitMQ: HTTP management API.
var INFRA_VERSION_CACHE = {};

function detectInfraVersionsOnce() {
  var exec = require('child_process').exec;
  return Promise.all([
    // Docker Engine version — CLI once at startup only
    new Promise(function (resolve) {
      exec('docker version --format "{{.Server.Version}}"',
        { encoding: 'utf8', timeout: 4000, windowsHide: true },
        function (err, out) { resolve(!err && String(out).trim() ? String(out).trim().split('\n')[0] : null); });
    }),
    // PostgreSQL version — CLI once at startup only
    new Promise(function (resolve) {
      exec('psql --version',
        { encoding: 'utf8', timeout: 4000, windowsHide: true },
        function (err, out) {
          if (err || !String(out).trim()) return resolve(null);
          var m = String(out).match(/(\d+\.\d+(?:\.\d+)?)/);
          resolve(m ? m[1] : null);
        });
    }),
    // Redis version — docker exec once at startup only
    new Promise(function (resolve) {
      exec('docker exec sme-redis redis-cli info server',
        { encoding: 'utf8', timeout: 4000, windowsHide: true },
        function (err, out) {
          if (err || !String(out).trim()) return resolve(null);
          var m = String(out).match(/redis_version:([^\r\n]+)/);
          resolve(m ? m[1].trim() : null);
        });
    }),
    // RabbitMQ version — HTTP management API /api/overview (no Docker CLI)
    httpGetWithAuth(15672, '/api/overview', 'smeadmin', 'smeadmin123').then(function (data) {
      return (data && data.rabbitmq_version) ? data.rabbitmq_version : null;
    }).catch(function () { return null; }),
  ]).then(function (results) {
    INFRA_VERSION_CACHE['Docker']     = results[0];
    INFRA_VERSION_CACHE['PostgreSQL'] = results[1];
    INFRA_VERSION_CACHE['Redis']      = results[2];
    INFRA_VERSION_CACHE['RabbitMQ']   = results[3];
    console.log('[monitor] infra versions cached (startup):', JSON.stringify(INFRA_VERSION_CACHE));
  });
}

// ── HTTP GET with Basic Auth — used for RabbitMQ management API ───────────────
function httpGetWithAuth(port, urlPath, username, password) {
  return new Promise(function (resolve) {
    var done = false;
    function finish(r) { if (!done) { done = true; clearTimeout(wall); resolve(r); } }
    var wall = setTimeout(function () { try { req.destroy(); } catch (_) {} finish(null); }, HEALTH_TIMEOUT);
    var auth = Buffer.from(username + ':' + password).toString('base64');
    var req  = http.request(
      { hostname: '127.0.0.1', port: port, path: urlPath, method: 'GET',
        headers: { 'Authorization': 'Basic ' + auth, 'Accept': 'application/json' } },
      function (res) {
        if (res.statusCode !== 200) { res.resume(); return finish(null); }
        var body = '';
        res.setEncoding('utf8');
        res.on('data', function (c) { body += c; if (body.length > 65536) req.destroy(); });
        res.on('end',  function () { try { finish(JSON.parse(body)); } catch (_) { finish(null); } });
      }
    );
    req.on('error', function () { finish(null); });
    req.end();
  });
}

// ── RabbitMQ aliveness probe — HTTP management API (Fix W6) ──────────────────
// GET /api/health/checks/aliveness/%2F  — returns { status:'ok' } on HTTP 200.
// No Docker CLI involved. Credentials: guest/guest (RabbitMQ default).
function probeRabbitMq() {
  return new Promise(function (resolve) {
    var done = false;
    function finish(r) { if (!done) { done = true; clearTimeout(wall); resolve(r); } }
    var wall = setTimeout(function () { try { req.destroy(); } catch (_) {} finish({ ok: false, code: 'timeout' }); }, HEALTH_TIMEOUT);
    var auth = Buffer.from('smeadmin:smeadmin123').toString('base64');
    var req  = http.request(
      { hostname: '127.0.0.1', port: 15672,
        path: '/api/overview', method: 'GET',
        headers: { 'Authorization': 'Basic ' + auth } },
      function (res) { res.resume(); finish({ ok: res.statusCode === 200, code: res.statusCode }); }
    );
    req.on('error', function () { finish({ ok: false, code: null }); });
    req.end();
  });
}

// ── PostgreSQL readiness probe — SELECT 1 (Fix W4) ───────────────────────────
// Attempts pg module (pure-Node, zero subprocess). Falls back to psql SELECT 1
// if pg is not available. Never relies on TCP port open alone.
var _pgConnStr = null;
function getPostgresConnStr() {
  if (_pgConnStr !== null) return _pgConnStr;
  try {
    var content = fs.readFileSync(path.join(PROJECT_ROOT, 'apps/iam-service/.env'), 'utf8');
    var m = content.match(/DATABASE_URL\s*=\s*([^\r\n]+)/);
    _pgConnStr = (m ? m[1].trim() : '') || '';
  } catch (_) { _pgConnStr = ''; }
  return _pgConnStr;
}

function probePostgres() {
  return new Promise(function (resolve) {
    var connStr = getPostgresConnStr();
    // Prefer pg module — pure-Node, no subprocess at all
    var pg = null;
    try { pg = require('pg'); } catch (_) {}
    if (pg && connStr) {
      var client = new pg.Client({
        connectionString: connStr,
        connectionTimeoutMillis: HEALTH_TIMEOUT,
        query_timeout: HEALTH_TIMEOUT,
      });
      var settled = false;
      function done(ok) { if (!settled) { settled = true; try { client.end(); } catch (_) {} resolve(ok); } }
      setTimeout(function () { done(false); }, HEALTH_TIMEOUT + 300);
      client.connect(function (err) {
        if (err) return done(false);
        client.query('SELECT 1', function (err2) { done(!err2); });
      });
      return;
    }
    // Fallback: psql SELECT 1 (lightweight; only used when pg module absent)
    if (connStr) {
      var parsed = connStr.match(/^postgresql:\/\/([^:]+):([^@]+)@([^:\/]+):(\d+)\/([^?]+)/);
      if (parsed) {
        var env2 = Object.assign({}, process.env, {
          PGPASSWORD: parsed[2], PGCONNECT_TIMEOUT: '2', PGAPPNAME: 'sme-monitor',
        });
        require('child_process').execFile(
          'psql', ['-h', parsed[3], '-p', parsed[4], '-U', parsed[1], '-d', parsed[5],
                   '-t', '-A', '--no-psqlrc', '-c', 'SELECT 1'],
          { encoding: 'utf8', timeout: 3000, windowsHide: true, env: env2 },
          function (err, stdout) { resolve(!err && stdout.trim() === '1'); }
        );
        return;
      }
    }
    // Last resort: TCP port check (weakest but never crashes)
    probeTcp(5432).then(function (r) { resolve(r === 'ok'); });
  });
}

// ── Find PID on port — PowerShell Get-NetTCPConnection (replaces netstat) ────
// Used ONLY by the stop action. Not called during polling.
// Two-stage lookup: PowerShell Get-NetTCPConnection first, netstat -ano fallback.
// netstat works even when the process was launched in a different user session.
function findPidOnPort(port) {
  var p = parseInt(port, 10);
  return new Promise(function (resolve) {
    require('child_process').exec(
      'powershell -NonInteractive -Command "(Get-NetTCPConnection -LocalPort ' + p +
        ' -State Listen -ErrorAction SilentlyContinue | Select-Object -First 1).OwningProcess"',
      { encoding: 'utf8', timeout: 3000, windowsHide: true },
      function (err, stdout) {
        if (!err && stdout.trim()) {
          var pid1 = parseInt(stdout.trim(), 10);
          if (pid1 > 0) {
            console.log('[findPidOnPort] Get-NetTCPConnection => PID ' + pid1 + ' on :' + p);
            return resolve(pid1);
          }
        }
        // Fallback: netstat -ano — robust across admin/non-admin, IPv4 + IPv6
        console.log('[findPidOnPort] Get-NetTCPConnection found nothing on :' + p + ', trying netstat fallback');
        require('child_process').exec(
          'netstat -ano',
          { encoding: 'utf8', timeout: 6000, windowsHide: true },
          function (err2, out2) {
            if (err2) {
              console.log('[findPidOnPort] netstat error:', err2.message);
              return resolve(null);
            }
            var needle = ':' + p + ' ';
            var lines  = (out2 || '').split('\n');
            for (var i = 0; i < lines.length; i++) {
              var line = lines[i];
              if (line.indexOf(needle) !== -1 && line.indexOf('LISTENING') !== -1) {
                var parts = line.trim().split(/\s+/);
                var pid2  = parseInt(parts[parts.length - 1], 10);
                if (pid2 > 0) {
                  console.log('[findPidOnPort] netstat fallback => PID ' + pid2 + ' on :' + p);
                  return resolve(pid2);
                }
              }
            }
            console.log('[findPidOnPort] no LISTENING process found on :' + p + ' via netstat either');
            resolve(null);
          }
        );
      }
    );
  });
}

// Quick HTTP probe — returns true if ANYTHING responds on that port.
// Used to cross-check after findPidOnPort returns null.
// Check if an HTTP service is genuinely alive — probes /health/live then /health then /
// Uses the same timeout as the dashboard health poll so both agree on running/stopped.
// Path order: /health/live (NestJS), /health (generic), / (last resort).
function checkPortAlive(port) {
  var p = parseInt(port, 10);
  var paths = ['/health/live', '/health', '/'];
  var idx = 0;
  return new Promise(function (resolve) {
    function tryNext() {
      if (idx >= paths.length) {
        console.log('[checkPortAlive] port ' + p + ' — all paths timed out / refused → dead');
        return resolve(false);
      }
      var probePath = paths[idx++];
      var settled = false;
      function done(alive, reason) {
        if (settled) return; settled = true;
        console.log('[checkPortAlive] port ' + p + ' path=' + probePath + ' → ' + (alive ? 'ALIVE' : 'dead') + (reason ? ' (' + reason + ')' : ''));
        if (alive) return resolve(true);
        tryNext(); // try next path on failure
      }
      var timer = setTimeout(function () { try { req.destroy(); } catch (_) {} done(false, 'timeout'); }, HEALTH_TIMEOUT + 500);
      var req = http.get(
        { hostname: '127.0.0.1', port: p, path: probePath, timeout: HEALTH_TIMEOUT },
        function (r) { r.resume(); clearTimeout(timer); done(true, 'HTTP ' + r.statusCode); }
      );
      req.on('error', function (e) { clearTimeout(timer); done(false, e.code || e.message); });
    }
    tryNext();
  });
}

// ── Tech Stack Reference – declared versions from package.json files ────────────
function getTechStack() {
  var stack = { node: process.versions.node, nestjs: null, nextjs: null, typescript: null, prisma: null };
  var clean = function (v) { return v ? String(v).replace(/[\^~>=< ]/g, '') : null; };
  try {
    var pkg  = JSON.parse(fs.readFileSync(path.join(PROJECT_ROOT, 'package.json'), 'utf8'));
    var deps = Object.assign({}, pkg.dependencies || {}, pkg.devDependencies || {});
    stack.nestjs     = clean(deps['@nestjs/common']);
    stack.typescript = clean(deps['typescript']);
    stack.prisma     = clean(deps['@prisma/client']);
  } catch (_) {}
  // Next.js is a frontend dependency — read from web-admin package.json
  try {
    var webPkg  = JSON.parse(fs.readFileSync(path.join(PROJECT_ROOT, 'apps', 'web-admin', 'package.json'), 'utf8'));
    var webDeps = Object.assign({}, webPkg.dependencies || {}, webPkg.devDependencies || {});
    stack.nextjs = webDeps['next'] ? clean(webDeps['next']) : null;
  } catch (_) {}
  return stack;
}

// ── Database Schema Validator ───────────────────────────────────────────────
// Uses psql (via child_process) to query information_schema.tables.
// Reads DATABASE_URL from each service .env so credentials are never hard-coded.
// Completely non-crashing: every failure path returns status:'offline'.
function getDbSchemaHealth() {
  var SCHEMAS = [
    { name: 'iam',    envFile: 'apps/iam-service/.env'    },
    { name: 'tenant', envFile: 'apps/tenant-service/.env' },
    { name: 'config', envFile: 'apps/config-service/.env' },
    { name: 'audit',  envFile: 'apps/audit-service/.env'  },
  ];

  function parseDatabaseUrl(raw) {
    var m = String(raw).match(/^postgresql:\/\/([^:]+):([^@]+)@([^:\/]+):(\d+)\/([^?]+)/);
    if (!m) return null;
    return { user: m[1], password: m[2], host: m[3], port: parseInt(m[4], 10), database: m[5] };
  }

  function readConn(envFile) {
    try {
      var content = fs.readFileSync(path.join(PROJECT_ROOT, envFile), 'utf8');
      var m = content.match(/DATABASE_URL\s*=\s*([^\r\n]+)/);
      if (m) return parseDatabaseUrl(m[1].trim());
    } catch (_) {}
    return null;
  }

  function queryTables(conn, schemaName) {
    return new Promise(function (resolve) {
      var sql = "SELECT table_name FROM information_schema.tables WHERE table_schema='public' AND table_type='BASE TABLE' ORDER BY table_name;";
      var env = Object.assign({}, process.env, {
        PGPASSWORD:        conn.password,
        PGCONNECT_TIMEOUT: '2',
        PGAPPNAME:         'sme-monitor',
      });
      var args = ['-h', conn.host, '-p', String(conn.port), '-U', conn.user,
                  '-d', conn.database, '-t', '-A', '--no-psqlrc', '-c', sql];
      require('child_process').execFile(
        'psql', args,
        { encoding: 'utf8', timeout: 4000, windowsHide: true, env: env },
        function (err, stdout) {
          if (err) {
            var msg = String(err.message || '').split('\n')[0].replace(/password|PGPASSWORD/ig, '***').substring(0, 120);
            return resolve({ schema: schemaName, db: conn.database, status: 'offline', count: 0, tables: [], error: msg });
          }
          var tables = stdout.trim().split('\n').map(function (l) { return l.trim(); }).filter(Boolean);
          resolve({ schema: schemaName, db: conn.database,
                    status: tables.length > 0 ? 'ready' : 'empty',
                    count:  tables.length, tables: tables });
        }
      );
    });
  }

  return Promise.all(SCHEMAS.map(function (s) {
    var conn = readConn(s.envFile);
    if (!conn) {
      return Promise.resolve({ schema: s.name, db: '(no .env)', status: 'offline',
                               count: 0, tables: [], error: 'DATABASE_URL not found in ' + s.envFile });
    }
    return queryTables(conn, s.name);
  }));
}

