// ── API Gateway Pre-Flight Checks ─────────────────────────────────────────────
// Probes three categories:
//   1. Gateway Health  — public GET endpoints on :3000 (no auth needed)
//   2. Gateway Routes  — authenticated routes; 401 = route + auth guard wired
//   3. Direct Services — each microservice /health on its native port
async function getPreflightChecks() {
  var checks = [
    // Gateway Health (Public — no token required)
    { id: 'gw-live',    label: '/health/live',                  port: 3000, path: '/health/live',    expectPass: [200] },
    { id: 'gw-ready',   label: '/health/ready',                 port: 3000, path: '/health/ready',   expectPass: [200], expectWarn: [503] },
    { id: 'gw-health',  label: '/health',                       port: 3000, path: '/health',         expectPass: [200] },
    { id: 'gw-docs',    label: '/docs (Swagger UI)',             port: 3000, path: '/docs',           expectPass: [200, 301, 302] },
    // Gateway Routes (authenticated — 401 confirms route + guard loaded)
    { id: 'gw-authme',  label: '/auth/me',                      port: 3000, path: '/auth/me',        expectPass: [401] },
    { id: 'gw-profile', label: '/school/profile',               port: 3000, path: '/school/profile', expectPass: [401] },
    // Direct Service Health (bypasses gateway — each service native port)
    { id: 'svc-iam',    label: 'iam-service :3001 /health/live',     port: 3001, path: '/health/live',         expectPass: [200] },
    { id: 'svc-tenant', label: 'tenant-service :3002 /health/live',  port: 3002, path: '/health/live',         expectPass: [200] },
    { id: 'svc-config', label: 'config-service :3003 /health/live',  port: 3003, path: '/health/live',         expectPass: [200] },
    { id: 'svc-audit',  label: 'audit-service :3004 /health/live',   port: 3004, path: '/health/live',         expectPass: [200] },
    { id: 'svc-portal', label: 'portal-service :3005 /health/live',  port: 3005, path: '/health/live',         expectPass: [200] },
  ];
  return Promise.all(checks.map(function (chk) {
    return probeHttp(chk.port, chk.path).then(function (r) {
      var result;
      if (r.code === 'timeout' || r.code === null) {
        result = 'fail';
      } else if (chk.expectPass.indexOf(r.code) !== -1) {
        result = 'pass';
      } else if (chk.expectWarn && chk.expectWarn.indexOf(r.code) !== -1) {
        result = 'warn';
      } else if (r.ok) {
        result = 'warn'; // HTTP < 500 but unexpected code
      } else {
        result = 'fail';
      }
      return { id: chk.id, label: chk.label, port: chk.port, path: chk.path, status: r.code, result: result };
    });
  }));
}


async function gatherStatus() {
  const t0 = Date.now();
  const pidRegistry = readPidRegistry(); // snapshot once for entire poll cycle
  // All infra versions are pre-cached at startup — zero CLI calls in this loop.
  const [dbSchemas, preflightChecks] = await Promise.all([
    getDbSchemaHealth(),
    getPreflightChecks(),
  ]);
  console.log('[monitor] db+preflight probes: ' + (Date.now() - t0) + 'ms');

  const t1 = Date.now();
  const components = await Promise.all(COMPONENTS.map(async function (c) {
    const tc = Date.now();

    // ── Docker daemon — Engine API over named pipe (zero CLI, Fix #093) ────
    // GET /info via \\.\pipe\docker_engine — pure http.request, no subprocess
    if (c.healthType === 'docker-daemon') {
      const daemonOk = await probeDockerDaemon();
      console.log('[monitor]   ' + ('Docker:').padEnd(20) + (Date.now() - tc) + 'ms  daemon=' + daemonOk);
      return {
        type: 'Infra', name: 'Docker', port: null, site: null, pid: null, inDocker: false,
        status: daemonOk ? 'running' : 'stopped',
        health: daemonOk ? 'API /info OK' : null,
        dockerStatus: null,
        version: INFRA_VERSION_CACHE['Docker'] || null,
      };
    }

    // Docker check (async Ã¢â‚¬â€œ fast docker CLI call)
    // ── RabbitMQ — HTTP Management API aliveness probe (Fix W6) ──────────
    // GET /api/health/checks/aliveness/%2F  — no Docker CLI whatsoever
    if (c.healthType === 'rabbitmq-mgmt') {
      const r = await probeRabbitMq();
      const status = r.ok ? 'running' : 'stopped';
      const health = r.ok ? 'HTTP 200 (alive)' : (r.code === 'timeout' ? 'Timeout' : 'Stopped');
      console.log('[monitor]   ' + (c.name + ':').padEnd(20) + (Date.now() - tc) + 'ms  status=' + status);
      return {
        type: c.type, name: c.name, port: c.port, site: c.site, pid: null,
        status: status, health: health, dockerStatus: null, inDocker: c.inDocker || false,
        version: INFRA_VERSION_CACHE['RabbitMQ'] || null,
      };
    }

    // ── PostgreSQL — SELECT 1 readiness probe (Fix W4) ────────────────────
    // Verifies actual query capability, not just TCP port open.
    if (c.healthType === 'postgres') {
      const pgOk = await probePostgres();
      const status = pgOk ? 'running' : 'stopped';
      console.log('[monitor]   ' + (c.name + ':').padEnd(20) + (Date.now() - tc) + 'ms  pg=' + pgOk);
      return {
        type: c.type, name: c.name, port: c.port, site: c.site, pid: null,
        status: status, health: pgOk ? 'SELECT 1 OK' : 'Offline',
        dockerStatus: null, inDocker: c.inDocker || false,
        version: INFRA_VERSION_CACHE['PostgreSQL'] || null,
      };
    }

    // ── Redis — RESP PING/PONG L7 probe (Fix #093) ───────────────────────
    if (c.healthType === 'tcp') {
      const r = await probeRedisPing(c.port);
      const status = r === 'pong' ? 'running' : 'stopped';
      console.log('[monitor]   ' + (c.name + ':').padEnd(20) + (Date.now() - tc) + 'ms  redis=' + r);
      return {
        type: c.type, name: c.name, port: c.port, site: c.site, pid: null,
        status: status, health: r === 'pong' ? 'PONG OK' : (r === 'timeout' ? 'Timeout' : 'No PONG'),
        dockerStatus: null, inDocker: c.inDocker || false,
        version: INFRA_VERSION_CACHE[c.name] || null,
      };
    }

    // ── HTTP backends: GET /health/live — any HTTP < 500 = running ──────────
    // ── HTTP-root frontends: GET / — 200, 307, or 308 = running ─────────────
    //
    // ARCHITECTURAL MANDATE: Layer-7 is the SOLE source of truth.
    // If the HTTP probe succeeds the service is RUNNING, period.
    // A failed or stale PID check CANNOT downgrade a live HTTP response to STOPPED.
    //
    // State model:
    //   RUNNING — HTTP probe returned a success code (< 500, or redirect for frontends)
    //   BOOTING — HTTP probe failed but a known PID is still alive in the registry
    //   STOPPED — HTTP probe failed AND no live PID in registry
    if (c.healthType === 'http' || c.healthType === 'http-root') {
      const probePath = c.healthType === 'http-root' ? '/' : '/health/live';
      let r = { code: null, ok: false };
      try {
        r = await probeHttp(c.port, probePath);
      } catch (probeErr) {
        console.error('[monitor]   ' + c.name + ' HTTP probe exception: ' + probeErr.message);
      }

      // http-root: Next.js redirects (307/308) and 200 all confirm the process is up.
      const httpOk = c.healthType === 'http-root'
        ? (r.code === 200 || r.code === 307 || r.code === 308)
        : r.ok; // backends: any non-5xx response is healthy

      const savedPid   = pidRegistry[c.name] || null;
      // Cheap non-blocking signal-0 existence check — no WMI subprocess.
      // WMI identity verification is deliberately deferred to the sequential
      // self-heal pass below so it never blocks the parallel HTTP probe phase.
      let pidAlive     = false;
      let effectivePid = savedPid;
      if (savedPid) {
        try {
          process.kill(savedPid, 0);
          pidAlive = true;
        } catch (e) {
          if (e && e.code === 'EPERM') pidAlive = true; // EPERM = process alive, no permission to signal
          // ESRCH or other = process is gone; pidAlive stays false
        }
      }

      const httpPart = r.code === 'timeout' ? 'Timeout'
                     : r.code === null      ? 'No response'
                     : 'HTTP ' + r.code;

      // ── SOURCE-OF-TRUTH RULE ─────────────────────────────────────────────
      // httpOk=true  → service is RUNNING regardless of PID state.
      //   If PID is stale/missing, flag for async self-heal (no WMI blocking here).
      // httpOk=false → fall back to PID for BOOTING vs STOPPED.
      const tentativeStatus = httpOk
        ? 'running'
        : (pidAlive ? 'booting' : 'stopped');

      // Health summary string shown in the dashboard
      const tentativeHealth = pidAlive
        ? 'PID ' + effectivePid + ' | ' + httpPart
        : (httpOk ? httpPart + ' | PID pending' : httpPart);

      // Flag for sequential post-pass: HTTP up but registry PID is stale/absent.
      // Hot-reload during dev changes the PID — we must re-discover without blocking.
      const needsDiscovery = httpOk && !pidAlive;

      console.log('[monitor]   ' + (c.name + ':').padEnd(20) + (Date.now() - tc) + 'ms  code=' + r.code + '  pid=' + (effectivePid || 'none') + '  alive=' + pidAlive + '  http-ok=' + httpOk + '  status=' + tentativeStatus);
      return {
        type: c.type, name: c.name, port: c.port, site: c.site,
        pid: pidAlive ? effectivePid : null,
        status: tentativeStatus, health: tentativeHealth,
        dockerStatus: null, inDocker: c.inDocker || false,
        version: SERVICE_VERSIONS[c.name] || null,
        _httpOk: httpOk, _httpPart: httpPart, _needsDiscovery: needsDiscovery,
      };
    }

    // Fallback
    return {
      type: c.type, name: c.name, port: c.port, site: c.site, pid: null,
      status: 'stopped', health: null, dockerStatus: null, inDocker: c.inDocker || false, version: null,
    };
  }));

  // ── Sequential self-heal pass ─────────────────────────────────────────────
  // Runs AFTER all parallel HTTP probes complete — event loop is free for
  // blocking netstat/WMI calls. Handles two cases:
  //   1. HTTP OK + no registry PID   → hot-reload changed the PID; re-discover.
  //   2. HTTP OK + PID gone (ESRCH)  → same; registry is stale after hot-reload.
  // The service stays RUNNING throughout — the HTTP layer already confirmed it.
  for (let i = 0; i < components.length; i++) {
    const comp = components[i];
    if (!comp._needsDiscovery) continue;

    let discovered = null;
    try {
      discovered = discoverPidByPort(comp.port, comp.name);
    } catch (discoverErr) {
      console.error('[Auto-Heal] discoverPidByPort exception for ' + comp.name + ': ' + discoverErr.message);
    }

    if (discovered) {
      writePidRegistry(comp.name, discovered);
      comp.pid    = discovered;
      // Status stays 'running' — HTTP already confirmed the service is alive.
      comp.status = 'running';
      comp.health = 'PID ' + discovered + ' | ' + comp._httpPart;
      logMonitorEvent('[Auto-Heal] Updated registry with new PID ' + discovered + ' for ' + comp.name + ' (hot-reload detected)');
    } else {
      // Could not resolve a PID but HTTP is still OK — service is genuinely
      // running (e.g. spawned by an external script with a wrapper PID).
      // Keep status=running, mark PID as unknown until next cycle resolves it.
      comp.pid    = null;
      comp.status = 'running';
      comp.health = comp._httpPart + ' | PID unresolved';
      console.log('[Auto-Heal] ' + comp.name + ': HTTP OK but PID discovery failed — keeping RUNNING, will retry next cycle');
    }

    delete comp._needsDiscovery;
    delete comp._httpOk;
    delete comp._httpPart;
  }
  // Clean up internal flags from any remaining components
  for (let i = 0; i < components.length; i++) {
    delete components[i]._needsDiscovery;
    delete components[i]._httpOk;
    delete components[i]._httpPart;
  }
  console.log('[monitor] service probes: ' + (Date.now() - t1) + 'ms  |  total: ' + (Date.now() - t0) + 'ms');

  // ── State-transition logging ──────────────────────────────────────────────
  // Compare each service's new status with the previous cycle's status.
  // Only GENUINE transitions are logged — no noise from steady-state polls.
  for (let i = 0; i < components.length; i++) {
    const comp   = components[i];
    const prev   = previousStates[comp.name];
    const curr   = comp.status;
    if (prev !== undefined && prev !== curr) {
      const reason = (comp.health || 'unknown');
      logMonitorEvent(
        '[State Transition] ' + comp.name +
        '  ' + prev.toUpperCase() + ' → ' + curr.toUpperCase() +
        '  reason: ' + reason
      );
    }
    previousStates[comp.name] = curr;
  }

  // Prisma artifact check — verify the Windows query engine DLL exists (Fix W5).
  // Checking for query_engine-windows.dll.node confirms generation, not just the directory.
  const prismaClients = PRISMA_CLIENTS.map(function (p) {
    const engineFile = path.join(PROJECT_ROOT, p.clientPath, 'query_engine-windows.dll.node');
    const exists = fs.existsSync(engineFile);
    return { service: p.service, path: p.clientPath, status: exists ? 'generated' : 'missing' };
  });

  return {
    timestamp:       new Date().toISOString(),
    components:      components,
    prismaClients:   prismaClients,
    latestVersions:  LATEST_VER_CACHE.data,
    techStack:       getTechStack(),
    envHealth:       getEnvHealth(),
    dbSchemas:       dbSchemas,
    preflightChecks: preflightChecks,
  };
}

// ── Background status cache (avoids slow gatherStatus on every HTTP request) ──
var _statusCache    = null;
var _statusInFlight = false;

async function refreshStatusCache() {
  if (_statusInFlight) return;
  _statusInFlight = true;
  try {
    _statusCache = await gatherStatus();
  } catch (e) {
    console.error('[monitor] status cache error:', e.message);
  } finally {
    _statusInFlight = false;
  }
}

function startStatusRefreshLoop() {
  refreshStatusCache();
  setInterval(refreshStatusCache, 8000);
}

// ── SSE (Server-Sent Events) — Live process streaming ────────────────────────
const sseClients = new Set();
let   procIdSeq  = 0;
const procLog    = new Map(); // id → { id, name, lines, status, child, start, end, exitCode }

function broadcastSSE(obj) {
  const payload = 'data: ' + JSON.stringify(obj) + '\n\n';
  for (const res of sseClients) {
    try { res.write(payload); } catch (_) {}
  }
}

function stripAnsi(s) {
  return String(s).replace(/\x1B\[[0-9;]*[mGKHFJA-Z]/g, '').replace(/\r/g, '');
}

function startTrackedProcess(name, cmd, args, spawnOpts) {
  const id    = ++procIdSeq;
  const entry = { id, name, lines: [], status: 'running', start: Date.now(), end: null, exitCode: null, child: null };
  procLog.set(id, entry);
  broadcastSSE({ type: 'proc-start', id, name, ts: entry.start });

  const child = spawn(cmd, args, Object.assign({}, spawnOpts || {}, {
    stdio:       ['ignore', 'pipe', 'pipe'],
    windowsHide: true,
    cwd:         PROJECT_ROOT,
  }));
  entry.child = child;

  function handleStream(stream, chunk) {
    stripAnsi(chunk.toString()).split('\n').forEach(function (line) {
      if (stream === 'out' && !line.trim()) return; // skip blank stdout lines
      const obj = { ts: Date.now(), text: line, stream: stream };
      entry.lines.push(obj);
      if (entry.lines.length > 1000) entry.lines.shift(); // cap memory
      broadcastSSE({ type: 'proc-line', id: id, text: line, stream: stream, ts: obj.ts });
    });
  }

  child.stdout.on('data', function (d) { handleStream('out', d); });
  child.stderr.on('data', function (d) { handleStream('err', d); });
  child.on('close', function (code) {
    entry.status   = code === 0 ? 'done' : (code === null ? 'killed' : 'failed');
    entry.exitCode = code;
    entry.end      = Date.now();
    broadcastSSE({ type: 'proc-end', id: id, code: code, status: entry.status, ts: entry.end });
    setTimeout(function () { procLog.delete(id); }, 600000);
  });
  return id;
}

// Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// Action handlers Ã¢â‚¬â€ Start / Stop per component
// Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬

/**
 * Run a PowerShell command in a detached new console window.
 * Returns immediately; output appears in the new window.
 */
function runPsInNewWindow(title, psCommand) {
  const encoded = Buffer.from(psCommand, 'utf16le').toString('base64');
  const child = spawn('powershell.exe', [
    '-NoExit',
    '-EncodedCommand', encoded,
  ], {
    detached:  true,
    stdio:     'ignore',
    env:       { ...process.env, SME_WINDOW_TITLE: title },
  });
  child.unref();
}

/**
 * Run a command silently (hidden, no console window) and capture output.
 * Used for quick actions like docker stop / Start-Service where we don't need
 * a visible terminal but do want to return stdout/stderr to the dashboard.
 */
function runSilent(cmd, opts) {
  opts = opts || {};
  try {
    const out = execSync(cmd, {
      encoding: 'utf8',
      timeout:  opts.timeout || 15000,
      cwd:      PROJECT_ROOT,
      windowsHide: true,
    });
    return { ok: true, output: out.trim() };
  } catch (e) {
    return { ok: false, output: (e.stderr || e.message || '').trim() };
  }
}

async function handleAction(name, action) {
  const comp = COMPONENTS.find(function (c) { return c.name === name; });
  if (!comp) return { ok: false, message: 'Unknown component: ' + name };

  // Ã¢â€â‚¬Ã¢â€â‚¬ STOP Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
  // ── Docker Desktop ────────────────────────────────────────────────────────
  if (comp.name === 'Docker') {
    if (action === 'stop') {
      return { ok: false, message: 'Docker Desktop cannot be stopped from this monitor. Use the Docker Desktop system tray icon.' };
    }
    if (action === 'start') {
      const ddPaths = [
        'C:\\Program Files\\Docker\\Docker\\Docker Desktop.exe',
        (process.env.LOCALAPPDATA || '') + '\\Docker\\Docker Desktop.exe',
        (process.env.ProgramFiles  || '') + '\\Docker\\Docker\\Docker Desktop.exe',
      ];
      for (const ddPath of ddPaths) {
        if (ddPath && fs.existsSync(ddPath)) {
          const child = spawn(ddPath, [], { detached: true, stdio: 'ignore' });
          child.unref();
          return { ok: true, message: 'Docker Desktop is starting\u2026 This may take 30\u201360 seconds. Wait for the Docker status to show \u201crunning\u201d before starting Redis or RabbitMQ.' };
        }
      }
      // Fallback: try via PowerShell Start-Process (resolves shell associations)
      const r = runSilent('powershell -NonInteractive -Command "Start-Process \'Docker Desktop\'"');
      if (r.ok) {
        return { ok: true, message: 'Docker Desktop launch requested. Wait 30\u201360 seconds for it to be ready.' };
      }
      return { ok: false, message: 'Could not find Docker Desktop executable. Please start Docker Desktop manually from the Start Menu.' };
    }
  }

  // ── STOP ──────────────────────────────────────────────────────────────────
  if (action === 'stop') {
    if (comp.docker) {
      // Docker container Ã¢â‚¬â€ stop gracefully
      const r = runSilent('docker stop ' + comp.docker);
      if (!r.ok) {
        const hint = /cannot connect|is not running|daemon/i.test(r.output)
          ? ' Docker Desktop does not appear to be running. Start Docker Desktop first.'
          : '';
        return { ok: false, message: r.output + hint };
      }
      return { ok: true, message: comp.docker + ' stopped.' };
    }

    if (comp.name === 'PostgreSQL') {
      const r = runSilent(
        'powershell -NonInteractive -Command "Stop-Service -Name (Get-Service postgresql* | Select-Object -First 1).Name -Force"'
      );
      return { ok: r.ok, message: r.ok ? 'PostgreSQL service stopped.' : r.output };
    }

    // Backend / Frontend — kill by registry PID first, fall back to port
    // Registry kill is precise (exact process), port kill covers any edge case.
    const regStop   = readPidRegistry();
    const savedPid  = regStop[comp.name];
    if (savedPid && isNodeAlive(savedPid, comp.name)) {
      try { process.kill(savedPid); } catch (_) {}
      clearPidRegistry(comp.name);
      return { ok: true, message: comp.name + ' stopped (PID ' + savedPid + ' terminated).' };
    }
    // PID not registered or already dead — fall back to port-based kill
    if (!comp.port) { clearPidRegistry(comp.name); return { ok: false, message: 'No port defined for ' + comp.name }; }
    killByPort(comp.port);
    clearPidRegistry(comp.name);
    return { ok: true, message: comp.name + ' stopped (killed process on port ' + comp.port + ').' };

  // Ã¢â€â‚¬Ã¢â€â‚¬ START Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
  }
  if (action === 'start') {
    if (comp.docker) {
      const r = runSilent('docker start ' + comp.docker);
      if (!r.ok) {
        const hint = /cannot connect|is not running|daemon/i.test(r.output)
          ? ' Docker Desktop does not appear to be running \u2014 use the Docker row in this dashboard to start it, then retry.'
          : '';
        return { ok: false, message: r.output + hint };
      }
      return { ok: true, message: comp.docker + ' started.' };
    }

    if (comp.name === 'PostgreSQL') {
      const r = runSilent(
        'powershell -NonInteractive -Command "Start-Service -Name (Get-Service postgresql* | Select-Object -First 1).Name"'
      );
      return { ok: r.ok, message: r.ok ? 'PostgreSQL service started.' : r.output };
    }

    // Backend / Frontend -- start directly (native Node.js)
    if (!comp.port) return { ok: false, message: 'No port defined for ' + comp.name };
    if (!SERVICE_SCRIPT_MAP[comp.name]) {
      return { ok: false, message: 'No script mapping for ' + comp.name };
    }
    return startServiceDirect(comp.name);
  }

  // ── RESTART ───────────────────────────────────────────────────────────────
  if (action === 'restart') {
    if (comp.docker) {
      const r = runSilent('docker restart ' + comp.docker);
      return { ok: r.ok, message: r.ok ? comp.docker + ' restarted.' : r.output };
    }
    if (comp.name === 'PostgreSQL') {
      const r = runSilent(
        'powershell -NonInteractive -Command "Restart-Service -Name (Get-Service postgresql* | Select-Object -First 1).Name -Force"'
      );
      return { ok: r.ok, message: r.ok ? 'PostgreSQL service restarted.' : r.output };
    }
    if (!SERVICE_SCRIPT_MAP[comp.name] && !comp.docker && comp.name !== 'PostgreSQL') {
      return { ok: false, message: 'No script mapping for ' + comp.name };
    }
    // Backend / Frontend — kill by registry PID + port, then restart directly
    if (SERVICE_SCRIPT_MAP[comp.name]) {
      // Kill by registry PID first (targeted), then port (belt-and-suspenders)
      const regRestart  = readPidRegistry();
      const restartPid  = regRestart[comp.name];
      if (restartPid && isNodeAlive(restartPid, comp.name)) {
        try { process.kill(restartPid); } catch (_) {}
      }
      if (comp.port) killByPort(comp.port);
      clearPidRegistry(comp.name); // clear so startServiceDirect skips idempotency guard
      await new Promise(function (r) { setTimeout(r, 1500); }); // brief pause for port to free
      const restartResult = startServiceDirect(comp.name);
      return restartResult.ok
        ? { ok: true, message: comp.name + ' restarted. ' + restartResult.message }
        : restartResult;
    }
    return { ok: false, message: 'Restart not supported for ' + comp.name };
  }

  return { ok: false, message: 'Unknown action: ' + action };
}

/**
 * Run a platform script (prep / boot / fullboot) piped into the Live Console.
 */
function handleScript(script) {
  const scripts = {
    prep:     { file: 'prepsme.ps1',     label: 'SME Prep'      },
    boot:     { file: 'bootsme.ps1',     label: 'SME Boot'      },
    fullboot: { file: 'sme-fullboot.ps1', label: 'SME Full Boot' },
  };
  const entry = scripts[script];
  if (!entry) return { ok: false, message: 'Unknown script: ' + script };

  const scriptPath = path.join(PROJECT_ROOT, entry.file);
  if (!fs.existsSync(scriptPath)) {
    return { ok: false, message: entry.file + ' not found at ' + scriptPath };
  }

  const procId = startTrackedProcess(
    entry.label,
    'powershell.exe',
    ['-ExecutionPolicy', 'Bypass', '-File', scriptPath],
    {}
  );
  return { ok: true, message: entry.label + ' started \u2014 streaming to Live Console.', procId: procId };
}

// Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// Body reader helper
// Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
function readBody(req) {
  return new Promise(function (resolve, reject) {
    let body = '';
    req.on('data', function (chunk) {
      body += chunk;
      if (body.length > 4096) { reject(new Error('Request body too large')); req.destroy(); }
    });
    req.on('end',   function () { resolve(body); });
    req.on('error', reject);
  });
}

// Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// Embedded HTML Dashboard v2 Ã¢â‚¬â€ with controls
// Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// --------------------------------------------------------------------------
// Server-side HTML generation helpers (run once at startup, baked into HTML)
// --------------------------------------------------------------------------
function ssE(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function ssRowId(name) { return name.replace(/[^a-z0-9]/gi,'-').toLowerCase(); }
function ssTypeBadge(t) {
  var map = {Infra:'bi',Backend:'bb',Frontend:'bf',Code:'bc'};
  return '<span class="badge '+(map[t]||'bc')+'">'+t+'</span>';
}
function ssSiteCell(site, type) {
  if (!site) return '<span class="site-addr">&mdash;</span>';
  if (type === 'Backend' || type === 'Frontend')
    return '<a class="site-link" href="http://'+site+'" target="_blank" rel="noopener">'+ssE(site)+'</a>';
  return '<span class="site-addr">'+ssE(site)+'</span>';
}
function ssSectionHdr(icon, title, extra) {
  return '<div class="section-hdr">'
    +'<div class="section-title">'+icon+'&nbsp;&nbsp;'+ssE(title)+'</div>'
    +'<div class="section-line"></div>'
    +(extra ? '<div class="section-actions">'+extra+'</div>' : '')
    +'</div>';
}
function ssComponentTable(rows) {
  var h = '<table><thead><tr><th>Type</th><th>Component</th><th>Version</th><th>Port</th>'
    +'<th>Site Address</th><th>PID</th><th>Status</th><th>Health</th><th>Actions</th></tr></thead><tbody>';
  for (var i=0;i<rows.length;i++) {
    var c=rows[i], id=ssRowId(c.name);
    h += '<tr id="row-'+id+'">'
      +'<td>'+ssTypeBadge(c.type)+'</td>'
      +'<td class="name-cell">'+ssE(c.name)+'</td>'
      +'<td id="ver-'+id+'"><span class="skel" style="width:44px"></span></td>'
      +'<td class="port-num">:'+c.port+'</td>'
      +'<td>'+ssSiteCell(c.site,c.type)+'</td>'
      +'<td id="pid-'+id+'"><span class="skel" style="width:40px"></span></td>'
      +'<td id="status-'+id+'"><span class="skel" style="width:68px"></span></td>'
      +'<td id="health-'+id+'"><span class="skel" style="width:52px"></span></td>'
      +'<td id="actions-'+id+'"><div class="row-actions">'
      +'<button class="btn btn-green btn-sm" disabled>&#9654; Start</button>'
      +'<button class="btn btn-red btn-sm" disabled>&#9632; Stop</button>'
      +'</div></td></tr>';
  }
  return h+'</tbody></table>';
}
function ssInfraTable(rows) {
  var h = '<table><thead><tr><th>Type</th><th>Component</th><th>Version</th><th>Latest</th><th>Port</th>'
    +'<th>Site Address</th><th>PID</th><th>Status</th><th>Health</th><th>Actions</th></tr></thead><tbody>';
  for (var i=0;i<rows.length;i++) {
    var c=rows[i], id=ssRowId(c.name);
    var nameHtml = c.inDocker ? '<span class="in-docker-icon">&#8627;</span>&nbsp;'+ssE(c.name) : ssE(c.name);
    var portHtml = c.port ? ':'+c.port : '<span class="ver-na">&mdash;</span>';
    var siteHtml = c.site ? ssSiteCell(c.site,c.type) : '<span class="ver-na">&mdash;</span>';
    var rowCls   = c.inDocker ? ' class="in-docker-row"' : '';
    h += '<tr id="row-'+id+'"'+rowCls+'>';
    h += '<td>'+ssTypeBadge(c.type)+'</td>';
    h += '<td class="name-cell">'+nameHtml+'</td>';
    h += '<td id="ver-'+id+'"><span class="skel" style="width:52px"></span></td>';
    h += '<td id="latest-'+id+'"><span class="skel" style="width:52px"></span></td>';
    h += '<td class="port-num">'+portHtml+'</td>';
    h += '<td>'+siteHtml+'</td>';
    h += '<td id="pid-'+id+'"><span class="skel" style="width:40px"></span></td>';
    h += '<td id="status-'+id+'"><span class="skel" style="width:68px"></span></td>';
    h += '<td id="health-'+id+'"><span class="skel" style="width:52px"></span></td>';
    if (c.name === 'Docker') {
      h += '<td id="actions-'+id+'"><span class="ver-na">Desktop</span></td>';
    } else {
      h += '<td id="actions-'+id+'"><div class="row-actions">';
      h += '<button class="btn btn-green btn-sm" disabled>&#9654; Start</button>';
      h += '<button class="btn btn-red btn-sm" disabled>&#9632; Stop</button>';
      h += '</div></td>';
    }
    h += '</tr>';
  }
  return h+'</tbody></table>';
}
function ssPrismaTable(rows) {
  var h = '<table><thead><tr><th>Type</th><th>Service</th>'
    +'<th>Generated Client Path</th><th>Status</th></tr></thead><tbody>';
  for (var i=0;i<rows.length;i++) {
    var p=rows[i], id=ssRowId(p.service);
    h += '<tr><td>'+ssTypeBadge('Code')+'</td>'
      +'<td class="name-cell">'+ssE(p.service)+'</td>'
      +'<td class="ppath">'+ssE(p.clientPath)+'</td>'
      +'<td id="prisma-'+id+'"><span class="skel" style="width:80px"></span></td></tr>';
  }
  return h+'</tbody></table>';
}
function ssStackWidget() {
  var items = [
    { id: 'node',       label: 'Node.js',    icon: '&#9096;'   },
    { id: 'nestjs',     label: 'NestJS',     icon: '&#128049;' },
    { id: 'nextjs',     label: 'Next.js',    icon: '&#9679;'   },
    { id: 'typescript', label: 'TypeScript', icon: '&#9775;'   },
    { id: 'prisma',     label: 'Prisma',     icon: '&#9670;'   },
  ];
  var h = '<div class="stack-grid">';
  for (var i = 0; i < items.length; i++) {
    var it = items[i];
    h += '<div class="stack-item">'
       + '<div class="stack-name">' + it.icon + '&nbsp;' + ssE(it.label) + '</div>'
       + '<div id="stack-' + it.id + '" class="stack-ver"><span class="skel" style="width:60px;height:16px"></span></div>'
       + '</div>';
  }
  return h + '</div>';
}
function ssDbSchemaTable() {
  var schemas = ['iam', 'tenant', 'config', 'audit'];
  var h = '<table><thead><tr>'
    + '<th>Schema</th><th>Database</th><th>Status</th>'
    + '<th style="text-align:center">Tables</th><th>Table Names</th>'
    + '</tr></thead><tbody>';
  for (var i = 0; i < schemas.length; i++) {
    var s = schemas[i];
    h += '<tr>'
       + '<td class="name-cell">' + s + '</td>'
      + '<td id="dbsch-db-'     + s + '" class="dbsch-db-col"><span class="skel" style="width:80px"></span></td>'
       + '<td id="dbsch-status-' + s + '"><span class="skel" style="width:90px"></span></td>'
       + '<td id="dbsch-count-'  + s + '" style="text-align:center"><span class="skel" style="width:20px"></span></td>'
       + '<td id="dbsch-tables-' + s + '"><span class="skel" style="width:220px"></span></td>'
       + '</tr>';
  }
  return h + '</tbody></table>';
}
function ssPreflightTable() {
  var rows = [
    { id: 'gw-live',    cat: 'gw',  catLabel: 'Gateway Health',   label: '/health/live',                   expect: '200' },
    { id: 'gw-ready',   cat: 'gw',  catLabel: 'Gateway Health',   label: '/health/ready',                  expect: '200 / 503' },
    { id: 'gw-health',  cat: 'gw',  catLabel: 'Gateway Health',   label: '/health',                        expect: '200' },
    { id: 'gw-docs',    cat: 'gw',  catLabel: 'Gateway Health',   label: '/docs (Swagger UI)',              expect: '200' },
    { id: 'gw-authme',  cat: 'rt',  catLabel: 'Gateway Routes',   label: '/auth/me  → expect 401',    expect: '401' },
    { id: 'gw-profile', cat: 'rt',  catLabel: 'Gateway Routes',   label: '/school/profile  → expect 401', expect: '401' },
    { id: 'svc-iam',    cat: 'svc', catLabel: 'Direct Services',  label: 'iam-service :3001 /health/live',      expect: '200' },
    { id: 'svc-tenant', cat: 'svc', catLabel: 'Direct Services',  label: 'tenant-service :3002 /health/live',   expect: '200' },
    { id: 'svc-config', cat: 'svc', catLabel: 'Direct Services',  label: 'config-service :3003 /health/live',  expect: '200' },
    { id: 'svc-audit',  cat: 'svc', catLabel: 'Direct Services',  label: 'audit-service :3004 /health/live',   expect: '200' },
    { id: 'svc-portal', cat: 'svc', catLabel: 'Direct Services',  label: 'portal-service :3005 /health/live',  expect: '200' },
  ];
  var catClass = { gw: 'pf-cat-gw', rt: 'pf-cat-rt', svc: 'pf-cat-svc' };
  var h = '<div class="pf-table-wrap"><table><thead><tr>'
    + '<th>Category</th><th>Endpoint</th><th>Expected</th><th>HTTP Status</th><th>Result</th>'
    + '</tr></thead><tbody>';
  for (var i = 0; i < rows.length; i++) {
    var r = rows[i];
    h += '<tr>'
       + '<td><span class="pf-cat ' + catClass[r.cat] + '">' + r.catLabel + '</span></td>'
       + '<td class="pf-lbl">' + ssE(r.label) + '</td>'
       + '<td class="pf-http">' + ssE(r.expect) + '</td>'
       + '<td id="pf-http-'   + r.id + '"><span class="skel" style="width:36px"></span></td>'
       + '<td id="pf-result-' + r.id + '"><span class="skel" style="width:60px"></span></td>'
       + '</tr>';
  }
  h += '</tbody></table></div>'
     + '<div class="pf-note-box">'
     + '<strong>&#128736; Architect&#39;s Note</strong> &mdash; '
     + 'The API Gateway uses an <strong>orchestration pattern</strong> (not a reverse-proxy). '
     + 'It does <em>not</em> expose transparent proxy routes like <code style="background:#0d1117;padding:1px 5px;border-radius:3px;font-size:11px">/api/iam/...</code>. '
     + 'Instead it holds typed HTTP clients (<code style="background:#0d1117;padding:1px 5px;border-radius:3px;font-size:11px">TenantClientService</code>, '
     + '<code style="background:#0d1117;padding:1px 5px;border-radius:3px;font-size:11px">IamTokenService</code>) '
     + 'and orchestrates calls to downstream services internally. '
     + 'Authenticated routes correctly return <strong>401</strong> when hit without a bearer token &mdash; '
     + 'a 401 confirms the route and auth guard are wired correctly; a 404 or 502 would indicate the gateway is down or the route is not registered.'
     + '</div>';
  return h;
}
function ssEnvGrid() {
  var items = [
    { name: 'api-gateway',    file: '.env'       },
    { name: 'iam-service',    file: '.env'       },
    { name: 'tenant-service', file: '.env'       },
    { name: 'config-service', file: '.env'       },
    { name: 'audit-service',  file: '.env'       },
    { name: 'portal-service', file: '.env'       },
    { name: 'web-admin',      file: '.env.local' },
    { name: 'web-portal',     file: '.env.local' },
  ];
  var h = '<div class="env-grid">';
  for (var i = 0; i < items.length; i++) {
    var it = items[i], eid = ssRowId(it.name);
    h += '<div class="env-item">'
       + '<div id="env-dot-' + eid + '" class="env-dot"></div>'
       + '<div class="env-info">'
       +   '<div class="env-svc">' + ssE(it.name) + '</div>'
       +   '<div class="env-fname">apps/' + ssE(it.name) + '/' + ssE(it.file) + '</div>'
       + '</div>'
       + '<div id="env-lbl-' + eid + '" class="env-lbl"><span class="skel" style="width:46px"></span></div>'
       + '</div>';
  }
  return h + '</div>';
}
