const server = http.createServer(async function (req, res) {
  const u = req.url.split('?')[0]; // strip query string

  // Ã¢â€â‚¬Ã¢â€â‚¬ GET / Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
  if (req.method === 'GET' && u === '/') {
    res.writeHead(200, {
      'Content-Type':           'text/html; charset=utf-8',
      'Cache-Control':          'no-cache, no-store',
      'X-Content-Type-Options': 'nosniff',
    });
    return res.end(HTML);
  }

  // Ã¢â€â‚¬Ã¢â€â‚¬ GET /api/status Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
  if (req.method === 'GET' && u === '/api/status') {
    try {
      const data = _statusCache || await gatherStatus();
      res.writeHead(200, {
        'Content-Type':           'application/json',
        'Cache-Control':          'no-cache, no-store',
        'X-Content-Type-Options': 'nosniff',
      });
      return res.end(JSON.stringify(data));
    } catch (err) {
      res.writeHead(500, { 'Content-Type': 'application/json' });
      return res.end(JSON.stringify({ error: err.message }));
    }
  }

  // Ã¢â€â‚¬Ã¢â€â‚¬ POST /api/action Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
  // ── POST /api/refresh — force immediate status gather and SSE push to all browser clients
  // Called by sme-fullboot.ps1 after each component comes UP so the dashboard updates live.
  if (req.method === 'POST' && u === '/api/refresh') {
    res.writeHead(200, { 'Content-Type': 'application/json', 'X-Content-Type-Options': 'nosniff' });
    res.end(JSON.stringify({ ok: true }));
    // Fire-and-forget: response is already sent; gather fresh status then broadcast.
    refreshStatusCache().then(function () {
      broadcastSSE({ type: 'refresh' });
    }).catch(function (e) { console.error('[monitor] forced refresh error:', e.message); });
    return;
  }

  if (req.method === 'POST' && u === '/api/action') {
    try {
      const raw  = await readBody(req);
      const body = JSON.parse(raw);
      const name   = String(body.name   || '').trim();
      const action = String(body.action || '').trim();

      // Input validation Ã¢â‚¬â€ only allow known, safe values
      if (!name || !action || !['start', 'stop', 'restart'].includes(action)) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        return res.end(JSON.stringify({ ok: false, message: 'Invalid action or name.' }));
      }
      // Name must match a component in our manifest
      const validNames = COMPONENTS.map(function (c) { return c.name; });
      if (!validNames.includes(name)) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        return res.end(JSON.stringify({ ok: false, message: 'Unknown component: ' + name }));
      }

      console.log('[action] REQUEST  ' + action.toUpperCase() + ' → ' + name);
      const result = await handleAction(name, action);
      console.log('[action] RESULT   ok=' + result.ok + '  msg=' + result.message);
      res.writeHead(200, {
        'Content-Type':           'application/json',
        'X-Content-Type-Options': 'nosniff',
      });
      return res.end(JSON.stringify(result));
    } catch (err) {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      return res.end(JSON.stringify({ ok: false, message: 'Bad request: ' + err.message }));
    }
  }

  // Ã¢â€â‚¬Ã¢â€â‚¬ POST /api/run-script Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
  if (req.method === 'POST' && u === '/api/run-script') {
    try {
      const raw    = await readBody(req);
      const body   = JSON.parse(raw);
      const script = String(body.script || '').trim();

      // Whitelist Ã¢â‚¬â€ only allow 'prep' or 'boot'
      if (!['prep', 'boot', 'fullboot'].includes(script)) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        return res.end(JSON.stringify({ ok: false, message: 'Unknown script: ' + script }));
      }

      const result = handleScript(script);
      res.writeHead(200, {
        'Content-Type':           'application/json',
        'X-Content-Type-Options': 'nosniff',
      });
      return res.end(JSON.stringify(result));
    } catch (err) {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      return res.end(JSON.stringify({ ok: false, message: 'Bad request: ' + err.message }));
    }
  }

  // ── GET /api/log-stream — SSE live process output ──────────────────────────
  if (req.method === 'GET' && u === '/api/log-stream') {
    res.writeHead(200, {
      'Content-Type':           'text/event-stream',
      'Cache-Control':          'no-cache',
      'Connection':             'keep-alive',
      'X-Accel-Buffering':      'no',
      'X-Content-Type-Options': 'nosniff',
    });
    res.write(': connected\n\n');
    // Replay active process logs for late-joining clients
    for (const entry of procLog.values()) {
      res.write('data: ' + JSON.stringify({ type: 'proc-start', id: entry.id, name: entry.name, ts: entry.start }) + '\n\n');
      for (const line of entry.lines) {
        res.write('data: ' + JSON.stringify({ type: 'proc-line', id: entry.id, text: line.text, stream: line.stream, ts: line.ts }) + '\n\n');
      }
      if (entry.status !== 'running') {
        res.write('data: ' + JSON.stringify({ type: 'proc-end', id: entry.id, code: entry.exitCode, status: entry.status, ts: entry.end }) + '\n\n');
      }
    }
    sseClients.add(res);
    req.on('close', function () { sseClients.delete(res); });
    return;
  }

  // ── GET /api/db/inspect — Quick Data Inspector ─────────────────────────────
  // Security: `db` is whitelisted; `table` is validated to [A-Za-z0-9_] only.
  if (req.method === 'GET' && u === '/api/db/inspect') {
    const VALID_INSPECT_DBS = ['iam', 'tenant', 'config', 'audit'];
    const ENV_FOR_DB = {
      iam:    'apps/iam-service/.env',
      tenant: 'apps/tenant-service/.env',
      config: 'apps/config-service/.env',
      audit:  'apps/audit-service/.env',
    };
    // Parse query params safely without importing url module
    var qstr = req.url.indexOf('?') !== -1 ? req.url.slice(req.url.indexOf('?') + 1) : '';
    var qparams = {};
    qstr.split('&').forEach(function (p) {
      var eq = p.indexOf('=');
      if (eq > 0) {
        try { qparams[decodeURIComponent(p.slice(0, eq))] = decodeURIComponent(p.slice(eq + 1)); }
        catch (_) {}
      }
    });
    var dbParam    = String(qparams.db    || '').trim();
    var tableParam = String(qparams.table || '').trim();

    if (!VALID_INSPECT_DBS.includes(dbParam)) {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      return res.end(JSON.stringify({ error: 'Invalid db. Must be one of: ' + VALID_INSPECT_DBS.join(', ') }));
    }
    // Strict table name whitelist — alphanumeric + underscore only (prevents SQL injection)
    if (!tableParam || !/^[A-Za-z0-9_]+$/.test(tableParam)) {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      return res.end(JSON.stringify({ error: 'Invalid table name. Only letters, digits and underscores are allowed.' }));
    }

    // Read DATABASE_URL from the service .env (same as queryTables — no pg module needed)
    var inspConn = null;
    try {
      var inspEnvRaw = fs.readFileSync(path.join(PROJECT_ROOT, ENV_FOR_DB[dbParam]), 'utf8');
      var inspMatch  = inspEnvRaw.match(/DATABASE_URL\s*=\s*([^\r\n]+)/);
      if (inspMatch) {
        var inspUrl = inspMatch[1].trim();
        var mConn   = inspUrl.match(/^postgresql:\/\/([^:]+):([^@]+)@([^:/]+):(\d+)\/([^?]+)/);
        if (mConn) inspConn = { user: mConn[1], password: mConn[2], host: mConn[3], port: parseInt(mConn[4], 10), database: mConn[5] };
      }
    } catch (_) {}

    if (!inspConn) {
      res.writeHead(500, { 'Content-Type': 'application/json' });
      return res.end(JSON.stringify({ error: 'Could not read DATABASE_URL for: ' + dbParam }));
    }

    // Use psql with --csv output — same technique as getDbSchemaHealth/queryTables
    // tableParam already validated as [A-Za-z0-9_] above — safe to double-quote
    var inspSql = 'SELECT * FROM "' + tableParam + '" LIMIT 100;';
    var inspEnv = Object.assign({}, process.env, {
      PGPASSWORD:        inspConn.password,
      PGCONNECT_TIMEOUT: '5',
      PGAPPNAME:         'sme-monitor-inspect',
    });
    var inspArgs = [
      '-h', inspConn.host,
      '-p', String(inspConn.port),
      '-U', inspConn.user,
      '-d', inspConn.database,
      '--csv',
      '--no-psqlrc',
      '-c', inspSql,
    ];
    require('child_process').execFile(
      'psql', inspArgs,
      { encoding: 'utf8', timeout: 10000, windowsHide: true, env: inspEnv },
      function (inspErr, stdout, stderr) {
      if (inspErr) {
        var msg = String(inspErr.message || stderr || '').split('\n')[0]
                    .replace(/password|PGPASSWORD/ig, '***').substring(0, 200);
        res.writeHead(500, { 'Content-Type': 'application/json' });
        return res.end(JSON.stringify({ error: msg }));
      }
      // Parse CSV output into rows[]
      var lines = stdout.trim().split('\n').filter(Boolean);
      if (lines.length === 0) {
        res.writeHead(200, { 'Content-Type': 'application/json', 'Cache-Control': 'no-cache, no-store', 'X-Content-Type-Options': 'nosniff' });
        return res.end(JSON.stringify({ rows: [], count: 0, db: dbParam, table: tableParam }));
      }
      // Simple CSV parser (handles RFC 4180 quoted fields)
      function parseCsvLine(line) {
        var result = [], cur = '', inQ = false;
        for (var ci = 0; ci < line.length; ci++) {
          var ch = line[ci];
          if (inQ) {
            if (ch === '"' && line[ci+1] === '"') { cur += '"'; ci++; }
            else if (ch === '"') { inQ = false; }
            else { cur += ch; }
          } else if (ch === '"') { inQ = true; }
          else if (ch === ',') { result.push(cur); cur = ''; }
          else { cur += ch; }
        }
        result.push(cur);
        return result;
      }
      var headers = parseCsvLine(lines[0].replace(/\r$/, ''));
      var rows    = [];
      for (var ri = 1; ri < lines.length; ri++) {
        var vals = parseCsvLine(lines[ri].replace(/\r$/, ''));
        var obj  = {};
        for (var ci2 = 0; ci2 < headers.length; ci2++) {
          obj[headers[ci2]] = vals[ci2] !== undefined ? vals[ci2] : null;
        }
        rows.push(obj);
      }
      res.writeHead(200, { 'Content-Type': 'application/json', 'Cache-Control': 'no-cache, no-store', 'X-Content-Type-Options': 'nosniff' });
      return res.end(JSON.stringify({ rows: rows, count: rows.length, db: dbParam, table: tableParam }));
      }
    );
    return; // response will be sent asynchronously by execFile callback above
  }

  // ── GET /db-inspect.html — Table inspector page ──────────────────────────
  if (req.method === 'GET' && u === '/db-inspect.html') {
    try {
      var htmlFile = fs.readFileSync(path.join(__dirname, 'db-inspect.html'), 'utf8');
      res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8', 'Cache-Control': 'no-cache, no-store' });
      return res.end(htmlFile);
    } catch (_) {
      res.writeHead(404);
      return res.end('db-inspect.html not found');
    }
  }

  res.writeHead(404);
  res.end('Not Found');
});

// Cache infrastructure versions once at startup — no repeated CLI polls (Fix W1/W6)
detectInfraVersionsOnce();
// Fetch latest versions from the internet in the background (non-blocking, every 6h)
startVersionRefreshLoop();
