server.listen(MONITOR_PORT, '127.0.0.1', function () {
  console.log('');
  console.log('  +------------------------------------------------------+');
  console.log('  |   SME Mission Control v2  --  Dashboard Ready        |');
  console.log('  +------------------------------------------------------+');
  console.log('  |   URL     : http://localhost:' + MONITOR_PORT + '                   |');
  console.log('  |   Press Ctrl+C to stop                               |');
  console.log('  +------------------------------------------------------+');
  console.log('');
  console.log('  Project : ' + PROJECT_ROOT);
  console.log('');
  // Auto-open the dashboard in the default browser (Windows)
  require('child_process').exec('start http://localhost:' + MONITOR_PORT, function (err) {
    if (err) console.log('  (Could not auto-open browser: ' + err.message + ')');
  });
});

server.on('error', function (err) {
  if (err.code === 'EADDRINUSE') {
    console.error('\n  ERROR: Port ' + MONITOR_PORT + ' is already in use.');
    console.error('  Kill the process on that port or change MONITOR_PORT in sme-monitor.js\n');
  } else {
    console.error('\n  Server error:', err.message, '\n');
  }
  process.exit(1);
});

